import axiosInstance from '../axiosConfig';
import React, { useState } from 'react';
import axios from '../axiosConfig'; 

const TaskForm = ({ onTaskAdded }) => {
  const [topic, setTopic] = useState('');
  const [description, setDescription] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!topic || !description) return alert("Please fill in both fields");

    try {
      // Now this 'axios.post' uses your special 5001 config automatically!
      const response = await axios.post('/api/tasks', { 
        title: topic, 
        description: description 
      });

      if (response.status === 201 || response.status === 200) {
        onTaskAdded(); 
        setTopic('');
        setDescription('');
      }
    } catch (error) {
      console.error("Error:", error);
      alert("Failed to post debate. Is the backend running on port 5001?");
    }
  };

return ( 
    <div className="bg-slate-100 p-8 rounded-xl shadow-inner border border-slate-200 mb-8">
      <h2 className="text-slate-800 text-2xl font-bold mb-6">Start a New Debate</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        {/* ... inputs ... */}
        <button type="submit" className="bg-slate-800 text-white p-3 rounded-lg w-full">
          Open Debate
        </button>
      </form>
    </div>
  ); 
};


export default TaskForm; // The ONLY default export!
